pins.content:
def pins(self, cid: str = None) -> Dict[str, Any]:
    """List pinned content on local IPFS node."""
    params = {}
    if cid:
        params['arg'] = cid
    response = self._post('/pin/ls', params=params, timeout=30)
    response.raise_for_status()
    data = response.json()
    if cid:
        keys = data.get('Keys', {})
        return {cid: keys.get(cid)} if cid in keys else {}
    return data

