def get_user(self) -> Dict[str, Any]:
    """Get current authenticated user info"""
    if not self.token:
        return {"status": "error", "message": "Not authenticated. Use auth() first."}

    response = requests.get(f"{self.base_url}/user", headers=self.headers)
