        'metadata': metadata or {}
    }

    if name == None:
        # 
        cnt = 0
        name = f'{user}{cnt}'
        while name in hosts:
            cnt += 1
            name = f'{user}{cnt}'
    hosts[name] = host
    self.save_hosts(hosts)
    return {'status': 'success', 'msg': f'Host {name} added', 'host': host, 'name': name}

