    try:
        if method == 'GET':
            resp = req.get(url, timeout=timeout)
        else:
            resp = req.post(url, json=params or {}, timeout=timeout)
        resp.raise_for_status()
        return resp.json()
    except Exception as e:
        return {'error': str(e)}

