unpause.content:
def unpause(self, chain_id=None, chain=None, **kwargs):
    cid = chain_id or self._chain_id(chain)
    if not cid:
        return {'error': 'chain_id or chain name required'}
    self._ensure_engine()
    tx = self.engine.unpause(int(cid))
